using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

var builder = WebApplication.CreateBuilder(args);
builder.Services.AddControllers();
builder.Services.AddSingleton<ModelTrainingService>();
builder.Services.AddPredictionEnginePool<TicketInput, TicketPrediction>();

var app = builder.Build();

// Train model at startup and configure the prediction pool
var trainingService = app.Services.GetRequiredService<ModelTrainingService>();
trainingService.TrainAndEvaluate();

app.Services.GetRequiredService<PredictionEnginePool<TicketInput, TicketPrediction>>()
    .GetPredictionEngine(app.Services.GetRequiredService<ModelTrainingService>().ModelPath);

app.MapControllers();
app.Run();

